package com.enigma.familylinklite.services;

import android.app.*;import android.app.admin.DevicePolicyManager;import com.enigma.familylinklite.AdminReceiver;import com.enigma.familylinklite.MainActivity;import com.enigma.familylinklite.core.AppConfig;import com.enigma.familylinklite.security.CryptoUtils;import android.content.*;import android.content.pm.*;import android.app.usage.*;import android.media.*;import android.net.wifi.WifiManager;import android.os.*;import org.json.*;import java.io.*;import java.net.*;import java.nio.charset.StandardCharsets;import java.security.*;import java.util.*;import javax.crypto.*;import javax.crypto.spec.*;

public class ChildServerService extends Service{
    static final int PORT=AppConfig.COMMAND_PORT; static final String CHANNEL="child_server"; volatile boolean running=false; volatile boolean alarm=false; ServerSocket serverSocket; ToneGenerator tone; int previousDndFilter=-1; byte[] key; Thread serverThread; Thread discoveryThread; Thread volumeThread; WifiManager.WifiLock wifiLock; PowerManager.WakeLock wakeLock; Map<String,Long> blockedIps=new HashMap<>(); Set<String> recentCommands=Collections.synchronizedSet(new LinkedHashSet<String>()); static final int PROTOCOL_VERSION=AppConfig.PROTOCOL_VERSION; static final int MIN_PROTOCOL=AppConfig.MIN_SUPPORTED_PROTOCOL; static final String APP_VERSION=AppConfig.APP_VERSION; static final String CAPABILITIES=AppConfig.CAPABILITIES;
    public IBinder onBind(Intent i){return null;}
    public int onStartCommand(Intent intent,int flags,int startId){
        if(intent!=null&&"STOP_PING".equals(intent.getAction())){stopAlarm();broadcast("Ping stopped by child");return START_STICKY;}
        try{key=Base64.getDecoder().decode(getSharedPreferences("p",0).getString("key", ""));}catch(Exception e){broadcast("No pairing key found. Open Child mode once.");stopSelf();return START_NOT_STICKY;}
        startForeground(1, notification("Parental-Link child server running", "Listening on port "+PORT));
        acquireLocks();
        if(serverThread==null||!serverThread.isAlive()){running=true;serverThread=new Thread(this::runServer,"Parental-LinkChildServer");serverThread.start();startDiscovery();startVolumeEnforcer();broadcast("Server start requested");}else broadcast("Server already running");
        return START_STICKY;
    }
    public void onCreate(){super.onCreate();createChannel();}
    public void onDestroy(){running=false;try{if(serverSocket!=null)serverSocket.close();}catch(Exception ignored){}stopAlarm();releaseLocks();super.onDestroy();}
    void acquireLocks(){try{WifiManager wm=(WifiManager)getApplicationContext().getSystemService(WIFI_SERVICE);wifiLock=wm.createWifiLock(WifiManager.WIFI_MODE_FULL_HIGH_PERF,"Parental-LinkWifiLock");wifiLock.setReferenceCounted(false);wifiLock.acquire();}catch(Exception e){broadcast("Wi-Fi lock unavailable: "+e.getMessage());}try{PowerManager pm=(PowerManager)getSystemService(POWER_SERVICE);wakeLock=pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK,"Parental-Link:ChildServer");wakeLock.setReferenceCounted(false);wakeLock.acquire();}catch(Exception e){broadcast("Wake lock unavailable: "+e.getMessage());}}
    void releaseLocks(){try{if(wifiLock!=null&&wifiLock.isHeld())wifiLock.release();}catch(Exception ignored){}try{if(wakeLock!=null&&wakeLock.isHeld())wakeLock.release();}catch(Exception ignored){}}
    void runServer(){
        try{serverSocket=new ServerSocket();serverSocket.setReuseAddress(true);serverSocket.bind(new InetSocketAddress(PORT));broadcast("Server running in background on port "+PORT);while(running){Socket s=serverSocket.accept();handleSocket(s);}}
        catch(BindException e){broadcast("Server already active on port "+PORT+". Force stop the app if commands fail.");}
        catch(Exception e){if(running)broadcast("Server stopped: "+e.getMessage());}
    }
    void handleSocket(Socket s){String ip="";try{ip=s.getInetAddress().getHostAddress();Long until=blockedIps.get(ip);if(until!=null&&until>System.currentTimeMillis()){s.close();return;}BufferedReader r=new BufferedReader(new InputStreamReader(s.getInputStream()));String line=r.readLine();PrintWriter w=new PrintWriter(s.getOutputStream(),true);if(line!=null&&line.startsWith("PAIR|")){w.println(handlePair(line,ip));s.close();return;}String json;try{json=decrypt(line);}catch(Exception bad){blockedIps.put(ip,System.currentTimeMillis()+60000);broadcast("Bad handshake from "+ip+". Blocked for 60 seconds.");s.close();return;}String resp=handle(new JSONObject(json));w.println(encrypt(resp));s.close();}catch(Exception e){try{s.close();}catch(Exception ignored){}broadcast("Command error: "+e.getMessage());}}

    void startDiscovery(){if(discoveryThread!=null&&discoveryThread.isAlive())return;discoveryThread=new Thread(()->{int[] burst={0,5,15};for(int delay:burst){if(!running)return;try{Thread.sleep(delay*1000L);}catch(Exception ignored){}sendDiscovery();}while(running){try{Thread.sleep(60000);}catch(Exception ignored){}sendDiscovery();}},"Parental-LinkDiscovery");discoveryThread.start();}
    void sendDiscovery(){try{String payload="FLITE|1|"+PORT+"|"+pairingId();byte[] data=payload.getBytes(StandardCharsets.UTF_8);DatagramSocket ds=new DatagramSocket();ds.setBroadcast(true);DatagramPacket p=new DatagramPacket(data,data.length,InetAddress.getByName("255.255.255.255"),AppConfig.DISCOVERY_PORT);ds.send(p);ds.close();}catch(Exception e){broadcast("Discovery broadcast failed: "+e.getMessage());}}
    String pairingId(){return CryptoUtils.pairingId(key);}
    String handlePair(String line,String ip){try{String[] p=line.split("\\|");String code=p.length>1?p[1].replaceAll("\\D",""):"";String parentId=p.length>2?p[2]:"";if(code.equals(currentPairCode(key))){getSharedPreferences("p",0).edit().putBoolean("childConnected",true).putString("parentDeviceId",parentId).putString("parentName",getSharedPreferences("p",0).getString("parentName","Parent Control")).apply();broadcast("Pairing approved for "+ip);return "OK|"+Base64.getEncoder().encodeToString(key)+"|"+pairingId()+"|"+APP_VERSION+"|"+PROTOCOL_VERSION+"|"+MIN_PROTOCOL+"|"+CAPABILITIES;}blockedIps.put(ip,System.currentTimeMillis()+60000);broadcast("Wrong pairing code from "+ip+". Blocked for 60 seconds.");return "NO|wrong-code";}catch(Exception e){return "NO|"+e.getMessage();}}
    static String currentPairCode(byte[] k){return CryptoUtils.currentPairCode(k);}
    String handle(JSONObject j)throws Exception{int otherProtocol=j.optInt("protocol",1);int otherMin=j.optInt("minProtocol",1);if(PROTOCOL_VERSION<otherMin||otherProtocol<MIN_PROTOCOL)return "Update required: incompatible protocol";String commandId=j.optString("id","");if(commandId.length()>0){if(recentCommands.contains(commandId))return "Duplicate command ignored";recentCommands.add(commandId);if(recentCommands.size()>200){Iterator<String> it=recentCommands.iterator();if(it.hasNext()){it.next();it.remove();}}}String type=j.optString("type"),value=j.optString("value");if(type.equals("call_child")){showIncomingCall();showCommandNotification("Incoming parent call","Parent wants to call this device.");return "Incoming call shown";}if(type.equals("message")){showFullScreen("Message from parent",value,false);showCommandNotification("Message from parent",value);return "Message shown";}if(type.equals("set_parent_password")){String[] pp=value.split("\\|",2);String name=pp.length>0&&pp[0].length()>0?pp[0]:"Parent Control";String pass=pp.length>1?pp[1]:"";if(pass.length()>=4&&pass.length()<=6){getSharedPreferences("p",0).edit().putString("parentPassword",pass).putString("parentName",name).apply();return "Parent password saved";}return "Invalid parent password";}if(type.equals("otp_generate")){String who=value!=null&&value.length()>0?value:"Parent Control";String code=String.format(java.util.Locale.US,"%06d",new java.security.SecureRandom().nextInt(1000000));getSharedPreferences("p",0).edit().putString("childOtp",code).putString("childOtpParent",who).apply();broadcast("One-time unlock code generated for "+who);return "OTP:"+code;}if(type.equals("ping")){if(value.equals("start"))startAlarm();else stopAlarm();return "Ping "+value;}if(type.equals("dnd_allow_ping")){return allowPingThroughDnd();}if(type.equals("dnd_restore")){return restoreDndFilter();}if(type.equals("volume")){return handleVolumeCommand(value);} if(type.equals("hello")){return "VERSION: "+APP_VERSION+"\nPROTOCOL: "+PROTOCOL_VERSION+"\nCAPABILITIES: "+CAPABILITIES+"\nPERMISSIONS: "+permissionStatus()+"\nDND: "+dndStatus()+"\n";}if(type.equals("usage")){return usageToday();}if(type.equals("current_app")){return "CURRENT_APP: "+currentApp();}if(type.equals("block_current")){String app=currentPackage();if(app.length()==0)return "No current app detected. Enable Usage Access on the tablet.";String res=blockApp(app,1440);showFullScreen("App blocked",appLabel(app)+" is blocked until tomorrow.",true);return res;}if(type.equals("timeout_app")){String[] parts=value==null?new String[0]:value.split("\\|",2);String app=parts.length>0?parts[0].trim():"";int mins=30;try{if(parts.length>1)mins=Integer.parseInt(parts[1].trim());}catch(Exception ignored){}if(app.length()==0)return "No app provided";return blockApp(app,Math.max(1,mins));}if(type.equals("lock_screen")){return lockNow("Parent requested screen lock");}if(type.equals("lock_timeout")){int mins=0;try{mins=Integer.parseInt(value.trim());}catch(Exception ignored){}long until=System.currentTimeMillis()+Math.max(1,mins)*60000L;getSharedPreferences("rules",0).edit().putLong("lock_until",until).putString("lock_mode","timeout").apply();showFullScreen("Timeout active","This device is in timeout for "+Math.max(1,mins)+" minutes.",true);showCommandNotification("Tablet timeout", "Timeout active for "+Math.max(1,mins)+" minutes.");return "Timeout active for "+Math.max(1,mins)+" minutes";}if(type.equals("disable_use")){long until=System.currentTimeMillis()+24L*60L*60000L;getSharedPreferences("rules",0).edit().putLong("lock_until",until).putString("lock_mode","disable").apply();showFullScreen("Device disabled","Your parent disabled this device until tomorrow.",true);showCommandNotification("Device disabled", "Disabled until tomorrow.");return "Device disabled until tomorrow";}if(type.equals("enable_use")||type.equals("stop_timeout")){getSharedPreferences("rules",0).edit().remove("lock_until").remove("lock_mode").apply();sendBroadcast(new Intent("com.enigma.familylinklite.CLOSE_ATTENTION"));showCommandNotification("Device enabled", "Parental-Link disabled screen removed.");return "Device use enabled";}if(type.equals("update_prompt")){showCommandNotification("Parental-Link update", "Parent requests update to "+(value.length()>0?value:"the latest version")+". Open the parent release page and install when available.");return "Update prompt shown";}if(type.equals("child_audio_status")){return childAudioStatus();}if(type.equals("list_apps")){return installedAppsList();}if(type.equals("block_app")){return blockAppByPackage(value);}if(type.equals("timeout_current_app")){String app=currentPackage();if(app.length()==0)return "No current app detected. Enable Usage Access on the tablet.";int mins=30;try{mins=Integer.parseInt(value.trim());}catch(Exception ignored){}return blockApp(app,Math.max(1,mins));}if(type.equals("blocked_apps")){return blockedAppsList();}if(type.equals("unblock_app")){String pkg=value==null?"":value.trim();if(pkg.length()==0)return "No package provided";getSharedPreferences("rules",0).edit().remove("blocked_until_"+pkg).apply();broadcast("Unblocked app: "+pkg);return "Unblocked app: "+pkg;}if(type.equals("remove_all_limitations")){return removeAllLimitations("parent command");}if(type.equals("profile")){return applyProfile(value);}return "Unknown command";}
    String removeAllLimitations(String by){SharedPreferences prefs=getSharedPreferences("rules",0);SharedPreferences.Editor ed=prefs.edit();for(String k:prefs.getAll().keySet()){if(k.startsWith("blocked_until_"))ed.remove(k);}ed.remove("lock_until").remove("lock_mode").remove("active_profile").remove("profile_until").apply();sendBroadcast(new Intent("com.enigma.familylinklite.CLOSE_ATTENTION"));showCommandNotification("Travel mode", "All Parental-Link limitations removed.");broadcast("All limitations removed by "+by);return "All limitations removed";}
    String blockedAppsList(){Map<String,?> all=getSharedPreferences("rules",0).getAll();StringBuilder sb=new StringBuilder("Blocked apps:\n");long now=System.currentTimeMillis();int n=0;for(String k:all.keySet()){if(!k.startsWith("blocked_until_"))continue;long until=0;try{until=((Number)all.get(k)).longValue();}catch(Exception ignored){}if(until>now){String pkg=k.substring("blocked_until_".length());sb.append(appLabel(pkg)).append("|").append(pkg).append("|").append("until ").append(new java.text.SimpleDateFormat("HH:mm",java.util.Locale.US).format(new java.util.Date(until))).append("\n");n++;}}if(n==0)sb.append("No blocked apps");return sb.toString();}
    String blockAppByPackage(String value){String[] parts=value==null?new String[0]:value.split("\\|",2);String pkg=parts.length>0?parts[0].trim():"";int mins=1440;try{if(parts.length>1)mins=Integer.parseInt(parts[1].trim());}catch(Exception ignored){}if(pkg.length()==0)return "No package provided";return blockApp(pkg,Math.max(1,mins));}
    String blockApp(String pkg,int mins){long until=System.currentTimeMillis()+Math.max(1,mins)*60000L;getSharedPreferences("rules",0).edit().putLong("blocked_until_"+pkg,until).apply();showCommandNotification("App blocked", appLabel(pkg)+" blocked for "+Math.max(1,mins)+" minutes.");return "Blocked app: "+appLabel(pkg)+"|"+pkg;}
    String installedAppsList(){try{PackageManager pm=getPackageManager();java.util.List<ApplicationInfo> apps=pm.getInstalledApplications(0);java.util.Collections.sort(apps,(a,b)->appLabel(a.packageName).compareToIgnoreCase(appLabel(b.packageName)));StringBuilder sb=new StringBuilder("Apps:\n");int n=0;for(ApplicationInfo ai:apps){if(ai.packageName.equals(getPackageName()))continue;if((ai.flags&ApplicationInfo.FLAG_SYSTEM)!=0)continue;String label=appLabel(ai.packageName);if(label.length()==0)label=ai.packageName;sb.append(label.replace("|"," ")).append("|").append(ai.packageName).append("\n");if(++n>=120)break;}return sb.toString();}catch(Exception e){return "Error listing apps: "+e.getMessage();}}
    String appLabel(String pkg){try{PackageManager pm=getPackageManager();ApplicationInfo ai=pm.getApplicationInfo(pkg,0);return pm.getApplicationLabel(ai).toString();}catch(Exception e){return pkg==null?"":pkg;}}
    String childAudioStatus(){String ts=getSharedPreferences("p",0).getString("lastChildAudioMessage","");if(ts.length()==0)return "No child audio message ready.";return "Child audio message ready: "+ts;}
    void showFullScreen(String title,String text,boolean blocking){try{Intent i=new Intent(this, com.enigma.familylinklite.AttentionActivity.class);i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK|Intent.FLAG_ACTIVITY_CLEAR_TOP);i.putExtra("title",title);i.putExtra("text",text);i.putExtra("blocking",blocking);startActivity(i);}catch(Exception ignored){}}
    String applyProfile(String value){String profile=value==null?"":value.trim();SharedPreferences.Editor ed=getSharedPreferences("rules",0).edit();long now=System.currentTimeMillis();if(profile.equals("homework")){ed.putString("active_profile","homework").putLong("profile_until",now+2L*60L*60L*1000L).apply();showCommandNotification("Homework mode", "Homework mode active. Entertainment apps can be blocked in the next rules update.");return "Homework profile active";}if(profile.equals("bedtime")){ed.putString("active_profile","bedtime").putLong("profile_until",now+8L*60L*60L*1000L).putLong("lock_until",now+8L*60L*60L*1000L).putString("lock_mode","bedtime").apply();showCommandNotification("Bedtime mode", "Bedtime mode active.");return "Bedtime profile active";}if(profile.equals("free_time")){ed.putString("active_profile","free_time").remove("lock_until").apply();showCommandNotification("Free time", "Restrictions relaxed.");return "Free time profile active";}return "Unknown profile";}

    String lockNow(String reason){try{DevicePolicyManager dpm=(DevicePolicyManager)getSystemService(DEVICE_POLICY_SERVICE);ComponentName admin=new ComponentName(this,AdminReceiver.class);if(dpm!=null&&dpm.isAdminActive(admin)){dpm.lockNow();broadcast("Screen locked: "+reason);return "Screen locked";}showCommandNotification("Device admin needed", "Enable Device Admin for real screen lock.");return "Device admin not enabled; cannot lock screen";}catch(Exception e){return "Lock failed: "+e.getMessage();}}

    void showIncomingCall(){try{Intent i=new Intent(this, com.enigma.familylinklite.calls.CallActivity.class);i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK|Intent.FLAG_ACTIVITY_CLEAR_TOP);i.putExtra("mode","incoming");i.putExtra("parent",getSharedPreferences("p",0).getString("parentName","Parent"));startActivity(i);}catch(Exception ignored){}}
    String handleVolumeCommand(String value){try{String stream="media";int percent=50;String mode="set";if(value!=null&&value.contains("|")){String[] p=value.split("\\|");if(p.length>0)stream=p[0];if(p.length>1&&p[1].length()>0)percent=Integer.parseInt(p[1]);if(p.length>2)mode=p[2];}else percent=Integer.parseInt(value);stream=normalStreamName(stream);SharedPreferences rules=getSharedPreferences("rules",0);if("mute".equalsIgnoreCase(mode)){enableStickyMute(stream);return "Mute enforced for "+stream+". Previous level saved.";}if("unmute".equalsIgnoreCase(mode)){int restored=disableStickyMute(stream);return "Mute removed for "+stream+". Restored previous level: "+restored+"%";}rules.edit().putInt("volume_max_"+stream,percent).apply();if(!rules.getBoolean("volume_muted_"+stream,false))setVol(stream,percent,true);return "Volume "+stream+" "+mode+" set to "+percent+"%";}catch(Exception e){return "Volume command failed: "+e.getMessage();}}
    String normalStreamName(String stream){if(stream==null)return "media";stream=stream.toLowerCase(java.util.Locale.US);if(stream.contains("call"))return "calls";if(stream.contains("notification"))return "notifications";if(stream.contains("system"))return "system";return "media";}
    int streamId(String stream){stream=normalStreamName(stream);if(stream.contains("call"))return AudioManager.STREAM_VOICE_CALL;if(stream.contains("notification"))return AudioManager.STREAM_NOTIFICATION;if(stream.contains("system"))return AudioManager.STREAM_SYSTEM;return AudioManager.STREAM_MUSIC;}
    int currentVolumePercent(String stream){try{AudioManager a=(AudioManager)getSystemService(AUDIO_SERVICE);int sid=streamId(stream);int max=Math.max(1,a.getStreamMaxVolume(sid));return Math.round(a.getStreamVolume(sid)*100f/max);}catch(Exception e){return 0;}}
    void setVol(String stream,int percent,boolean unmute){AudioManager a=(AudioManager)getSystemService(AUDIO_SERVICE);int sid=streamId(stream);int max=a.getStreamMaxVolume(sid);int v=Math.max(0,Math.min(max,Math.round(max*percent/100f)));if(unmute){try{a.adjustStreamVolume(sid,AudioManager.ADJUST_UNMUTE,0);}catch(Exception ignored){}}a.setStreamVolume(sid,v,0);}
    void enableStickyMute(String stream){stream=normalStreamName(stream);SharedPreferences rules=getSharedPreferences("rules",0);int current=currentVolumePercent(stream);int savedPrev=rules.getInt("volume_prev_"+stream,-1);int prev=current>0?current:(savedPrev>0?savedPrev:Math.max(1,rules.getInt("volume_max_"+stream,50)));rules.edit().putBoolean("volume_muted_"+stream,true).putInt("volume_prev_"+stream,prev).apply();AudioManager a=(AudioManager)getSystemService(AUDIO_SERVICE);int sid=streamId(stream);try{a.adjustStreamVolume(sid,AudioManager.ADJUST_MUTE,0);}catch(Exception ignored){}a.setStreamVolume(sid,0,0);broadcast("Mute enforced: "+stream);}
    int disableStickyMute(String stream){stream=normalStreamName(stream);SharedPreferences rules=getSharedPreferences("rules",0);int prev=rules.getInt("volume_prev_"+stream,Math.max(1,rules.getInt("volume_max_"+stream,50)));int maxPct=rules.getInt("volume_max_"+stream,100);int restore=Math.max(0,Math.min(prev,maxPct));rules.edit().putBoolean("volume_muted_"+stream,false).apply();setVol(stream,restore,true);broadcast("Mute removed: "+stream+" restored to "+restore+"%");return restore;}
    void startVolumeEnforcer(){if(volumeThread!=null&&volumeThread.isAlive())return;volumeThread=new Thread(()->{while(running){try{Thread.sleep(2500);}catch(Exception ignored){}try{enforceVolume("media");enforceVolume("calls");enforceVolume("notifications");enforceVolume("system");}catch(Exception ignored){}}},"Parental-LinkVolumeEnforcer");volumeThread.start();}
    void enforceVolume(String stream){stream=normalStreamName(stream);SharedPreferences rules=getSharedPreferences("rules",0);AudioManager a=(AudioManager)getSystemService(AUDIO_SERVICE);int sid=streamId(stream);if(rules.getBoolean("volume_muted_"+stream,false)){int current=a.getStreamVolume(sid);boolean isMuted=false;try{isMuted=a.isStreamMute(sid);}catch(Exception ignored){}if(current>0||!isMuted){try{a.adjustStreamVolume(sid,AudioManager.ADJUST_MUTE,0);}catch(Exception ignored){}a.setStreamVolume(sid,0,0);broadcast("Mute restored by parent rule: "+stream);}return;}int maxPct=rules.getInt("volume_max_"+stream,-1);if(maxPct<0)return;int max=a.getStreamMaxVolume(sid);int current=a.getStreamVolume(sid);int allowed=Math.max(0,Math.min(max,Math.round(max*maxPct/100f)));if(current>allowed){a.setStreamVolume(sid,allowed,0);broadcast("Volume reduced to parent maximum: "+stream+" "+maxPct+"%");}}
    String permissionStatus(){boolean admin=false,usage=false,access=false,notif=true,overlay=false,dndPolicy=false;try{DevicePolicyManager dpm=(DevicePolicyManager)getSystemService(DEVICE_POLICY_SERVICE);admin=dpm!=null&&dpm.isAdminActive(new ComponentName(this,AdminReceiver.class));}catch(Exception ignored){}try{AppOpsManager a=(AppOpsManager)getSystemService(APP_OPS_SERVICE);usage=a.checkOpNoThrow(AppOpsManager.OPSTR_GET_USAGE_STATS,android.os.Process.myUid(),getPackageName())==AppOpsManager.MODE_ALLOWED;}catch(Exception ignored){}try{String enabled=android.provider.Settings.Secure.getString(getContentResolver(),android.provider.Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES);access=enabled!=null&&enabled.toLowerCase(java.util.Locale.US).contains(getPackageName().toLowerCase(java.util.Locale.US));}catch(Exception ignored){}try{if(Build.VERSION.SDK_INT>=33)notif=checkSelfPermission(android.Manifest.permission.POST_NOTIFICATIONS)==PackageManager.PERMISSION_GRANTED;}catch(Exception ignored){}try{overlay=android.provider.Settings.canDrawOverlays(this);}catch(Exception ignored){}try{NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);dndPolicy=nm!=null&&nm.isNotificationPolicyAccessGranted();}catch(Exception ignored){}return "admin="+admin+",usage="+usage+",accessibility="+access+",notifications="+notif+",overlay="+overlay+",dndPolicy="+dndPolicy;}
    String dndStatus(){try{NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);int filter=nm.getCurrentInterruptionFilter();boolean access=nm.isNotificationPolicyAccessGranted();String label="unknown";if(filter==NotificationManager.INTERRUPTION_FILTER_ALL)label="OFF";else if(filter==NotificationManager.INTERRUPTION_FILTER_PRIORITY)label="priority only";else if(filter==NotificationManager.INTERRUPTION_FILTER_ALARMS)label="alarms only";else if(filter==NotificationManager.INTERRUPTION_FILTER_NONE)label="total silence";return label+" / policy access "+(access?"yes":"no");}catch(Exception e){return "unknown";}}
    String allowPingThroughDnd(){try{NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);if(nm==null)return "DND service unavailable";if(!nm.isNotificationPolicyAccessGranted())return "DND policy access missing";previousDndFilter=nm.getCurrentInterruptionFilter();nm.setInterruptionFilter(NotificationManager.INTERRUPTION_FILTER_ALL);getSharedPreferences("rules",0).edit().putInt("previous_dnd_filter",previousDndFilter).apply();return "DND temporarily opened for ping";}catch(Exception e){return "DND change failed: "+e.getMessage();}}
    String restoreDndFilter(){try{NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);if(nm==null)return "DND service unavailable";int saved=getSharedPreferences("rules",0).getInt("previous_dnd_filter",previousDndFilter);if(nm.isNotificationPolicyAccessGranted()&&saved>0){nm.setInterruptionFilter(saved);getSharedPreferences("rules",0).edit().remove("previous_dnd_filter").apply();previousDndFilter=-1;return "DND restored";}return "DND restore skipped";}catch(Exception e){return "DND restore failed: "+e.getMessage();}}
    void setMediaVol(int percent){AudioManager a=(AudioManager)getSystemService(AUDIO_SERVICE);int max=a.getStreamMaxVolume(AudioManager.STREAM_MUSIC);int v=Math.max(0,Math.min(max,Math.round(max*percent/100f)));a.setStreamVolume(AudioManager.STREAM_MUSIC,v,0);}
    void startAlarm(){alarm=true;allowPingThroughDnd();try{AudioManager a=(AudioManager)getSystemService(AUDIO_SERVICE);int maxMusic=a.getStreamMaxVolume(AudioManager.STREAM_MUSIC);int maxAlarm=a.getStreamMaxVolume(AudioManager.STREAM_ALARM);int targetMusic=Math.max(1,Math.round(maxMusic*0.85f));int targetAlarm=Math.max(1,Math.round(maxAlarm*0.85f));a.adjustStreamVolume(AudioManager.STREAM_MUSIC,AudioManager.ADJUST_UNMUTE,0);a.adjustStreamVolume(AudioManager.STREAM_ALARM,AudioManager.ADJUST_UNMUTE,0);a.setStreamVolume(AudioManager.STREAM_MUSIC,targetMusic,0);a.setStreamVolume(AudioManager.STREAM_ALARM,targetAlarm,0);}catch(Exception ignored){}if(tone==null)tone=new ToneGenerator(AudioManager.STREAM_ALARM,80);showCommandNotification("Parent is pinging", "The tablet is playing a softer attention chime. Stop it from the tablet or parent phone.");try{Intent pi=new Intent(this, com.enigma.familylinklite.PingActivity.class);pi.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK|Intent.FLAG_ACTIVITY_CLEAR_TOP);startActivity(pi);}catch(Exception ignored){}new Thread(()->{while(alarm){try{tone.startTone(ToneGenerator.TONE_PROP_PROMPT,450);Thread.sleep(2600);}catch(Exception ignored){}}},"Parental-LinkPingChime").start();}
    void stopAlarm(){alarm=false;if(tone!=null)tone.stopTone();restoreDndFilter();}
    String currentApp(){String pkg=currentPackage();if(pkg.length()==0)return "Unavailable";try{PackageManager pm=getPackageManager();ApplicationInfo ai=pm.getApplicationInfo(pkg,0);return pm.getApplicationLabel(ai).toString()+" ("+pkg+")";}catch(Exception e){return pkg;}}
    String currentPackage(){try{UsageStatsManager us=(UsageStatsManager)getSystemService(USAGE_STATS_SERVICE);long end=System.currentTimeMillis();long start=end-5*60*1000;UsageEvents events=us.queryEvents(start,end);UsageEvents.Event ev=new UsageEvents.Event();String last="";long lastTime=0;while(events.hasNextEvent()){events.getNextEvent(ev);if(ev.getEventType()==UsageEvents.Event.MOVE_TO_FOREGROUND||ev.getEventType()==UsageEvents.Event.ACTIVITY_RESUMED){if(ev.getTimeStamp()>lastTime){lastTime=ev.getTimeStamp();last=ev.getPackageName();}}}return last==null?"":last;}catch(Exception e){return "";}}
    String usageToday(){try{UsageStatsManager us=(UsageStatsManager)getSystemService(USAGE_STATS_SERVICE);Calendar c=Calendar.getInstance();c.set(Calendar.HOUR_OF_DAY,0);c.set(Calendar.MINUTE,0);c.set(Calendar.SECOND,0);c.set(Calendar.MILLISECOND,0);List<UsageStats> stats=us.queryUsageStats(UsageStatsManager.INTERVAL_DAILY,c.getTimeInMillis(),System.currentTimeMillis());PackageManager pm=getPackageManager();stats.sort((a,b)->Long.compare(b.getTotalTimeInForeground(),a.getTotalTimeInForeground()));StringBuilder sb=new StringBuilder("VERSION: "+APP_VERSION+"\nPROTOCOL: "+PROTOCOL_VERSION+"\nCAPABILITIES: "+CAPABILITIES+"\nPERMISSIONS: "+permissionStatus()+"\nDND: "+dndStatus()+"\nCURRENT_APP: "+currentApp()+"\nUsage today:\n");int n=0;for(UsageStats st:stats){long mins=st.getTotalTimeInForeground()/60000;if(mins<1)continue;String name=st.getPackageName();try{ApplicationInfo ai=pm.getApplicationInfo(name,0);name=pm.getApplicationLabel(ai).toString();}catch(Exception ignored){}sb.append(name).append(": ").append(mins).append(" min\n");if(++n>=20)break;}if(n==0)sb.append("No usage data found. Enable Usage Access on the tablet.\n");return sb.toString();}catch(Exception e){return "Usage access not granted or unavailable: "+e.getMessage();}}
    String encrypt(String plain)throws Exception{return CryptoUtils.encryptAesGcm(key, plain);}
    String decrypt(String data)throws Exception{return CryptoUtils.decryptAesGcm(key, data);}
    void createChannel(){if(Build.VERSION.SDK_INT>=26){NotificationChannel ch=new NotificationChannel(CHANNEL,"Parental-Link Child Server",NotificationManager.IMPORTANCE_LOW);getSystemService(NotificationManager.class).createNotificationChannel(ch);}}
    Notification notification(String title,String text){Intent i=new Intent(this,MainActivity.class);PendingIntent pi=PendingIntent.getActivity(this,0,i,PendingIntent.FLAG_IMMUTABLE);return new Notification.Builder(this,CHANNEL).setContentTitle(title).setContentText(text).setSmallIcon(android.R.drawable.ic_dialog_info).setContentIntent(pi).setOngoing(true).build();}
    void showCommandNotification(String title,String text){NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);nm.notify(2,new Notification.Builder(this,CHANNEL).setContentTitle(title).setContentText(text).setStyle(new Notification.BigTextStyle().bigText(text)).setSmallIcon(android.R.drawable.ic_dialog_info).build());broadcast(title+": "+text);}
    void broadcast(String s){sendBroadcast(new Intent("com.enigma.familylinklite.LOG").putExtra("msg",s));}
}
